YAML:
"use client"

import * as React from "react" 

import { Toggle } from "@/components/ui/toggle"

export function ToggleDemo() {
  const [isPressed, setIsPressed] = React.useState(false)

  return (
    <Toggle 
      variant="outline" 
      pressed={isPressed} 
      onPressedChange={setIsPressed} 
      aria-label="Toggle On/Off"
      // Default outline variant handles visual state.
      // Add custom classes if needed:
      // className="data-[state=off]:bg-muted data-[state=off]:text-muted-foreground"
    >
       {/* Text changes based on state */}
       {isPressed ? "On" : "Off"}
    </Toggle>
  )
}

Description:
What this code does:
Theme Colors: Defines color schemes for both light and dark modes, including colors for the sidebar, text, backgrounds, and hover states.
Dark Mode Toggle: Initializes the gblDarkMode variable that controls the current theme.
Animation Support: Sets up gblThemeTimestamp for smooth theme transition animations.
Add the following code to your app's OnStart property to enable dark mode functionality:

// Theme Variables
Set(
    gblThemeColors,
    {
        light: {
            sidebarBackground: RGBA(237, 237, 237, 1),    // Light gray
            mainBackground: RGBA(255, 255, 255, 1),       // White
            textColor: RGBA(0, 0, 0, 1),                  // Black
            headerTextColor: RGBA(122, 138, 143, 1),      // Gray headers
            itemTextColor: RGBA(53, 61, 63, 1),           // Dark gray items
            borderColor: RGBA(214, 221, 224, 1),          // Light border
            hoverColor: RGBA(128, 128, 128, 0.3)         // Gray hover
        },
        dark: {
            sidebarBackground: RGBA(30, 41, 56, 1),      // Dark blue-gray
            mainBackground: RGBA(17, 24, 39, 1),         // Dark gray
            textColor: RGBA(255, 255, 255, 1),           // White
            headerTextColor: RGBA(156, 163, 175, 1),     // Light gray headers
            itemTextColor: RGBA(209, 213, 219, 1),       // Light gray items
            borderColor: RGBA(55, 65, 81, 1),            // Dark border
            hoverColor: RGBA(75, 85, 99, 0.5)           // Dark hover
        }
    }
);

// Initialize theme mode if not set
If(
    IsBlank(gblDarkMode),
    Set(gblDarkMode, false)
);

// Initialize theme timestamp for animations
If(
    IsBlank(gblThemeTimestamp),
    Set(gblThemeTimestamp, Text(Now(), "yyyymmddhhmmss"))
);
